class Solution {
public:
    int possibleStringCount(string word, int k) {
        const int MOD = 1e9 + 7;
        int n = word.size();
        vector<int> counts;
        int curr = 1;

        for (int i = 1; i <= n; ++i) {
            if (i == n || word[i] != word[i - 1]) {
                counts.push_back(curr);
                curr = 1;
            } else {
                curr++;
            }
        }

        int res = 1;
        int remaining = 0;

        for (int count : counts) {
            res = (res * (count + 1)) % MOD;
            remaining += count - 1;
        }

        for (int i = 0; i <= remaining; ++i) {
            if (n + i >= k) {
                res = (res - (i > 0 ? (res * pow(i, MOD - 2, MOD)) % MOD : 1)) % MOD;
            }
        }

        return (res + MOD) % MOD;
    }
};
